/**
 * Generates src/buildTime.ts from environment variables before packaging.
 *
 * Usage:
 *   pnpm write-config                     (CI — reads API_URL from env)
 *   API_URL=http://localhost:8080 pnpm write-config   (local dev)
 *
 * The generated file is committed as a placeholder (empty string) and
 * overwritten here. The real URL NEVER appears in committed source code.
 */

'use strict'

const fs   = require('fs')
const path = require('path')

// ── 1. Load .env for local development (no external dependency needed) ────────
function loadDotEnv(envPath) {
  try {
    const lines = fs.readFileSync(envPath, 'utf-8').split('\n')
    for (const line of lines) {
      const trimmed = line.trim()
      if (!trimmed || trimmed.startsWith('#')) continue
      const eqIdx = trimmed.indexOf('=')
      if (eqIdx === -1) continue
      const key = trimmed.slice(0, eqIdx).trim()
      const val = trimmed.slice(eqIdx + 1).trim().replace(/^["']|["']$/g, '')
      // Only set if not already in env (env takes precedence over .env file)
      if (!process.env[key]) process.env[key] = val
    }
  } catch {
    // .env file does not exist — that is fine in CI
  }
}

loadDotEnv(path.join(__dirname, '../.env'))

// ── 2. Validate required variables ───────────────────────────────────────────
const apiUrl = process.env.API_URL

if (!apiUrl) {
  console.error('')
  console.error('[write-build-config] ERROR: API_URL is not set.')
  console.error('[write-build-config] For local dev: add API_URL=<your-api> to apps/desktop-agent/.env')
  console.error('[write-build-config] For CI: set API_URL as a repository secret or workflow env var.')
  console.error('')
  process.exit(1)
}

// Basic validation — must be HTTPS in production
if (!apiUrl.startsWith('http')) {
  console.error(`[write-build-config] ERROR: API_URL must start with http(s)://. Got: ${apiUrl}`)
  process.exit(1)
}

// ── 3. Write the TypeScript source file ──────────────────────────────────────
const content = [
  `/**`,
  ` * AUTO-GENERATED by scripts/write-build-config.cjs — do not edit manually.`,
  ` * Generated at: ${new Date().toISOString()}`,
  ` * Source: API_URL environment variable (never committed)`,
  ` */`,
  `export const BUILD_API_URL = '${apiUrl}';`,
  '',
].join('\n')

const outPath = path.join(__dirname, '../src/buildTime.ts')
fs.writeFileSync(outPath, content, 'utf-8')

console.log(`[write-build-config] src/buildTime.ts written — API_URL: ${apiUrl}`)
